var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"하나, 둘, 셋~","JPN":"3、2、1、せーのっ！","ENG":"One, two, three...","TWN":"1、2、3～"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"퇴원 축하해! 레이첼 언니!","JPN":"退院おめでとう！　レイチェルお姉ちゃん！","ENG":"Welcome back! Rachel!","TWN":"瑞秋姊姊，恭喜你出院！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"다들 고마워! 보육원생 레이첼, 덕분에 멀쩡하게 복귀했습니다!","JPN":"みんなありがとう！　レイチェル・ドッズ、みんなのおかげで元気に復帰しました！","ENG":"Thank you, everyone. I'm out of the hospital and as good as new!","TWN":"謝謝大家，育幼院院生 瑞秋平安到家！"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 아야야야…….","JPN":"いたっ、いたたたた……","ENG":"Ow, owww...","TWN":"唉唷唷……"},"stage":{"bg":"DORMITORY_3","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"그렇게 까불다가 죽을 고비 넘겨 놓고서는 여전하다, 이것아.","JPN":"調子に乗りすぎてとんでもない目にあったくせに、変わらないなこいつは。","ENG":"Haven't you learned anything after almost getting yourself killed?","TWN":"你再這麼調皮，到時候又樂極生悲！"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"PRINCIPAL_NPC_ORPHAN_NULL","text":{"KOREA":"너 병원에 있을 때 그 의사 선생님한테 인사는 제대로 드렸니?","JPN":"入院していた時の担当の先生にはちゃんと挨拶してきたか？","ENG":"Did you even thank your doctor properly before you left?","TWN":"你在醫院時，有好好跟醫生打招呼嗎？"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"당연하죠. 오늘 퇴원할 때도 뵙고 왔는데요.","JPN":"もちろんです。さっき退院手続きする時も会ってきましたよ。","ENG":"Of course. I met her right before I left today.","TWN":"那當然囉！今天要出院時，我也有去跟醫生打招呼好嗎！"},"stage":{"bg":"DORMITORY_3","slots":{"L":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PRINCIPAL_NPC_ORPHAN_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"쾌유해서 다행이에요. 졸업한 학생들 만나러 <color=#ffd34c>우연히</color> 오지 않았더라면 큰일이었겠어요.","JPN":"快癒してよかったです。<color=#ffd34c>偶然</color>私が卒業生に会うためにこちらに来ていなかったら、大変なことになっていたと思います。","ENG":"Thank goodness you're all better now. It's a good thing that I <color=#ffd34c>happened to swing by</color> to meet some of my former students.","TWN":"恭喜你康復，要不是我<color=#ffd34c>剛好</color>來看畢業的學生，可就糟糕囉！"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"RACHEL_NPC_NULL_NULL","text":{"KOREA":"아, 네! 고맙습니다, 선생님!","JPN":"はい！　助かりました、先生！","ENG":"Oh, yes! Thank you, ma'am!","TWN":"是！謝謝醫生！"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"RACHEL_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"후훗. 뭘요. 오랜만에 저도 실력을 발휘할 수 있어서 의욕이 생기던 걸요.","JPN":"フフッ、こちらこそ、私も久しぶりに実力を発揮できていい刺激になりましたよ。","ENG":"Haha. No worries. I enjoyed the chance to brush up on my skills again too.","TWN":"呵呵，不用客氣，我也久違地可以這樣大展身手。"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"안 그러니, 제자야?","JPN":"そう思わない、弟子？","ENG":"Isn't that right, my dear protege?","TWN":"助教，你說對不對？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"하, 하하……. 네……. 그러니 제가 아직까지 붙어 있죠…….","JPN":"あ、はは……はい……だから私が辞めずに残っているわけです……","ENG":"Haha... Ha... Of course… Why else would I keep sticking around…","TWN":"哈，哈哈……對……否則我怎麼會還沒離開……"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"으응? 뭐라고?","JPN":"うん？　なんか言った？","ENG":"Huh? What was that?","TWN":"嗯？你說什麼？"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"LEEYOONJUNG_COFFIN_NULL_NULL","text":{"KOREA":"제, 제가 무슨 소리 했나요?! 아무것도 아닙니다!","JPN":"わ、私何か言いましたか！？　何でもないです！","ENG":"D-Did I say something?! It's nothing!","TWN":"我…我有說什麼嗎？我什麼都沒說！"},"stage":{"bg":"HOSPITAL","slots":{"L":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEYOONJUNG_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L26_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"몸에 후유증은 여전할 거예요. 대표적으로 그 등의 화상.","JPN":"後遺症は残るでしょう。例えばその背中の火傷。","ENG":"You'll still suffer from various sequelae. Especially that burn on your back.","TWN":"身體會留下後遺症，像是背上的燒傷。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OLIVIE_COFFIN_NULL_NULL","text":{"KOREA":"흉터는 물론이고, 정기적으로 병원에서 진찰 받아야 해요.","JPN":"傷跡はもちろん、定期的に病院で診察を受けなければなりません。","ENG":"It'll scar for sure. And you should get it periodically checked out at the hospital.","TWN":"疤是一定的，你要定期到醫院回診喔。"},"stage":{"bg":"HOSPITAL","slots":{"L":null,"C":{"char_id":"OLIVIE_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};